class Solution:
    def minimumDistance(self, word):
        from functools import lru_cache
        def dist(a, b):
            if a == 26 or b == 26:
                return 0
            return abs(a // 6 - b // 6) + abs(a % 6 - b % 6)
        letters = [ord(c) - 65 for c in word]
        n = len(letters)
        @lru_cache(maxsize=None)
        def go(i, f1, f2):
            if i == n:
                return 0
            c = letters[i]
            return min(dist(f1, c) + go(i + 1, c, f2),
                       dist(f2, c) + go(i + 1, f1, c))
        return go(0, 26, 26)

