class Solution:
    def minimumDistance(self, word):
        def dist(a, b):
            if a == 26 or b == 26:
                return 0
            return abs(a // 6 - b // 6) + abs(a % 6 - b % 6)
        INF = float('inf')
        dp = [INF] * 27
        dp[26] = 0
        for i in range(len(word) - 1):
            cur = ord(word[i]) - 65
            nxt = ord(word[i + 1]) - 65
            ndp = [INF] * 27
            for other in range(27):
                if dp[other] == INF:
                    continue
                # move current finger
                ndp[other] = min(ndp[other], dp[other] + dist(cur, nxt))
                # move other finger
                ndp[cur] = min(ndp[cur], dp[other] + dist(other, nxt))
            dp = ndp
        return min(dp)

