var minimumDistance = function(word) {
    function dist(a, b) {
        if (a === 26 || b === 26) return 0;
        return Math.abs(Math.floor(a / 6) - Math.floor(b / 6)) + Math.abs(a % 6 - b % 6);
    }
    const INF = Infinity;
    let dp = new Array(27).fill(INF);
    dp[26] = 0;
    for (let i = 0; i < word.length - 1; i++) {
        const cur = word.charCodeAt(i) - 65;
        const nxt = word.charCodeAt(i + 1) - 65;
        const ndp = new Array(27).fill(INF);
        for (let other = 0; other < 27; other++) {
            if (dp[other] === INF) continue;
            ndp[other] = Math.min(ndp[other], dp[other] + dist(cur, nxt));
            ndp[cur] = Math.min(ndp[cur], dp[other] + dist(other, nxt));
        }
        dp = ndp;
    }
    return Math.min(...dp);
};
